const a={name:"Savoykål",icon:"vegetable",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Savoykål kräver lite tålamod och god planering - hon vill ha näringsrik jord, jämn fukt och skydd mot kålfjärilen. Men hon är faktiskt snällare än vitkål, tåligare mot frost och förlåter fler misstag. Det krusiga bladverket gör henne till en riktig skönhet i landet.",zones:{outdoor:[1,2,3,4,5,6],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"90-140",spacing:"40-50 cm",rowSpacing:"50-60 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Savoykål vill ha ordentligt med ljus för att bygga sina vackra, krusiga huvuden. I halvskugga blir huvudena mindre och lösare - hon ger sitt bästa i full sol."},temperature:{min:-10,max:25,ideal:"12-18°C",detail:"Savoykål är en riktig nordbo som trivs bäst i svalka runt 12-18°C. Hon tål frost imponerande bra - härdade plantor klarar ner till -10°C! Det gör henne perfekt för sen höstskörd. Över 25°C stressar hon och tillväxten bromsas."},wind:{level:"Skyddat",detail:"De krusiga bladen fångar vind effektivt. Ge henne lite vindskydd, eller kupa jord runt stambasen för stabilitet. I utsatta lägen kan hon välta med sina tunga huvuden."}},watering:{need:"Medel-Hög",icon:"water",summary:"Savoykål vill ha jämn fukt hela säsongen, men de krusiga bladen gör henne lite bättre på att hålla fukt än slätbladig kål. Ojämn vattning kan ändå göra att huvudena spricker.",phases:[{phase:"Förodling (0-6 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men inte blöt. Kålfrön gror snabbt (5-10 dagar) vid rumstemperatur."},{phase:"Etablering (utplantering)",need:"Hög",tip:"Vattna rikligt vid utplantering och dagligen den första veckan. Nya kålplantor är törstiga och vill snabbt få fäste."},{phase:"Tillväxt och bladbildning",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon sitt fina, krusiga bladverk och varje blad som bildas blir en del av det kommande huvudet."},{phase:"Huvudbildning",need:"Hög",tip:"Kritisk period! Håll jämn fukt - plötsligt regn efter torka kan få huvudena att spricka. Hellre lite och ofta än stora svall."}],mistakes:["Ojämn vattning - torka följt av storvattning gör att huvudena spricker. Klassiskt nybörjarmisstag.","Vattna ovanifrån sent på kvällen - fuktiga krusiga blad torkar långsammare och bjuder in svampsjukdomar","Tro att kålen klarar sig själv bara för att hon ser tålig ut - speciellt under huvudbildningen behöver hon jämn fukt","Glömma bort vattning sent på hösten - savoykål som står kvar i kylan behöver fortfarande fukt"],tip:"Mulcha ordentligt med gräsklipp eller halm runt plantorna. De krusiga bladen samlar dagg naturligt, men rötterna behöver jämn markfukt. Mulchen hjälper enormt."},soil:"Näringsrik, kalkrik jord med bra struktur. Savoykål är en storätare precis som sin kusin vitkål, men hon trivs bra i lite lättare jord än ren lera.",soilTips:["Kalka på hösten om pH är under 6.5 - savoykål ÄLSKAR kalkrik jord och det skyddar mot klumprotsjuka","Blanda in rikligt med brunnen kompost och gärna lite hönsgödsel innan plantering. Hon äter för två.","Undvik packad jord - luckra djupt. De krusiga bladen signalerar en raffinerad dam, men under marken vill rötterna ha utrymme."],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jun",icon:"water"},{phase:"Bladtillväxt",months:"Jun-Jul",icon:"leaf"},{phase:"Skörd",months:"Aug-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Bladtillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd",months:"Sep-Nov",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Bladtillväxt",months:"Jul-Aug",icon:"leaf"},{phase:"Skörd",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Mar",N:15,P:10,K:10,label:"Förodling"},{month:"Apr",N:25,P:15,K:10,label:"Tillväxtstart"},{month:"Maj",N:55,P:25,K:20,label:"Utplantering"},{month:"Jun",N:80,P:35,K:30,label:"Kraftig bladtillväxt"},{month:"Jul",N:85,P:40,K:45,label:"Huvudbildning"},{month:"Aug",N:65,P:35,K:50,label:"Mognad"},{month:"Sep",N:35,P:25,K:40,label:"Sena sorter mognar"},{month:"Okt",N:15,P:15,K:25,label:"Höstskörd"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Savoykål behöver en kväverik start för att bygga alla de krusiga bladen som ska bli huvudet."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Hon ska vara i full gång nu och behöver bränsle för sin imponerande bladproduktion."},{timing:"Vid huvudbildning",tip:"Extra giva med kaliumrik gödsel (vedaska eller alggödsel). Kalium hjälper huvudet att bli tätt och förbättrar frosttåligheten."},{timing:"Sensommar",tip:"En sista lätt giva med kalium stärker cellväggarna och gör kålen ännu mer frosttålig. Perfekt timing inför hösten."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - den hittar helt enkelt inte kålen bland all lökdoft. Ett klassiskt knep."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dillen jobbar som kålens personliga livvakt."},{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft maskerar kålen för skadedjur. De trivs bra ihop och utnyttjar jorden på olika djup."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte utan kompletterar varandra fint."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De pratar helt enkelt olika språk - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir nöjd med den uppgörelsen."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte savoykål bredvid annan kål - de delar skadedjur och sjukdomar och förstärker varandras problem."}]},rotation:{avoid:[{id:"vitkal",name:"Vitkål"},{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"broccoli",name:"Broccoli"},{id:"rodkal",name:"Rödkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 4 år - helst 6-8 år - innan du odlar kål på samma plats igen. Klumprotsjuka lever kvar i jorden extremt länge.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga savoykål! Potatis och lök lämnar ren, väl bearbetad jord som kålen älskar.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden efter kål. Sallat gillar kvävet som kålen lämnar efter sig."},varieties:[{name:"Vertus 2",zones:[1,2,3,4,5,6],note:"Klassisk OP-sort med mörkgröna, krusiga blad och fasta huvuden. Milt och sött - den självklara savoykålen för svenska odlare. Finns hos Impecta."},{name:"Vorbote 3",zones:[1,2,3,4,5],note:"Tidig OP-sort som mognar snabbt. Kompakta, fina huvuden som är perfekta för den som vill ha tidig skörd. Funkar bra i kortare säsonger."},{name:"Wirosa F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med utmärkt köldhärdighet och kompakta, blågröna huvuden. Tål frost extremt bra och har lång ståndtid i fält. Välj denna om du vill ha maximal frosttålighet."},{name:"Deadon F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med utmärkt vinterhärdighet och vackra blågröna blad med lila ton. God sjukdomsresistens och fin smak. Ekofrö hos Semenco. OBS: F1 - ger inte sortäkta frö."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar stora hål i de krusiga bladen. Lämnar spillningshögar och kan förstöra plantor snabbt. Larverna gömmer sig extra bra bland savoykålens krusade bladverk.",fix:"Fiberduk från dag ett - det enda helt säkra skyddet! Handplocka larver regelbundet (kolla extra noga i vecken). Spruta med Bacillus thuringiensis (Bt) mot larverna. Samodla med dill och lök."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Rötterna är fulla av vita larver som äter sig igenom rotsystemet.",fix:"Kålkragar runt stjälken vid utplantering - hindrar flugan från att lägga ägg vid stambasen. Fiberduk hjälper också. Kraftiga plantor med bra rotsystem klarar lättare angrepp."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar i värme. Rötterna har fula, klumpiga svullnader. Kålodlarens absoluta mardröm.",fix:"Ingen bot - dra upp och bränn angripna plantor! Kalka jorden ordentligt (pH över 7). Odla inte kål på samma plats på minst 6-8 år. Svampen överlever i jorden extremt länge."},{name:"Jordloppor",symptom:"Små runda hål i unga blad, som om någon skjutit med hagelgevär. Värst i varmt, torrt väder. Unga plantor är mest utsatta.",fix:"Fiberduk är bästa skyddet. Håll jorden fuktig - jordloppor avskyr fukt. Pudra med stenmjöl eller vedaska. Starka, välgödda plantor klarar angrepp bättre."}],goodToKnow:[{icon:"warning",title:"Kalka - klumprotsjukans fiende",text:"Det absolut viktigaste du kan göra för kål är att kalka jorden. Klumprotsjuka trivs i sur jord och finns den väl i marken stannar den i 7+ år. Kalka på hösten, sikta på pH runt 7.",severity:"warning"},{icon:"snowflake",title:"Tål frost bättre än vitkål",text:"Savoykål är den frosttåligaste av huvudkålarna. Härdade plantor klarar ner till -10°C! De krusiga bladen fungerar som isolering och gör henne perfekt för sen höstskörd.",severity:"tip"},{icon:"warning",title:"Larverna gömmer sig i vecken",text:"De krusiga bladen är vackra men ger också kålfjärilens larver perfekta gömställen. Var extra noggrann när du letar larver - titta i varje veck och krås.",severity:"warning"},{icon:"leaf",title:"Mildare smak än vitkål",text:"Savoykål har en finare, mildare och sötare smak än vitkål. Perfekt i soppor, grytor och gratänger. Bladen blir silkeslena vid tillagning - en riktig höstfavorit i köket.",severity:"tip"},{icon:"harvest",title:"Frost gör henne ännu godare",text:"Precis som grönkål omvandlar savoykål stärkelse till socker vid frost. Vänta gärna med skörden till efter första frosten - smaken blir märkbart sötare.",severity:"tip"},{icon:"warning",title:"Lagras sämre än vitkål",text:"Savoykål håller sig inte lika länge som vitkål i källaren. Planera för att äta upp den inom några veckor efter skörd, eller frys in den direkt. Det krusiga bladverket gör henne mer känslig vid lagring.",severity:"warning"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Savoykål förodlas nästan alltid inomhus för att få tillräckligt lång säsong. Direktsådd fungerar i zon 1-3 men förodling ger bättre kontroll och tidigare skörd av de vackra, krusiga huvudena.",steps:["Så 1-2 cm djupt i krukor eller celler, 4-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (12-15°C) och starkt ljus så snart plantorna är uppe - det ger kompakta, starka plantor","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 40-50 cm avstånd när plantan har 4-6 riktiga blad","Tryck till jorden ordentligt runt stammen, vattna rikligt och sätt kålkragar + fiberduk direkt"],tips:["Savoykål kan även sås i juli för en sen höstskörd - välj tidiga sorter som Vorbote 3 för detta","Kålkragar runt stjälken vid utplantering skyddar mot kålfluga - gör dem av kartong, filt eller köp färdiga","Förodlade plantor som härdats ordentligt klarar frostknäppar mycket bättre efter utplantering"],indoorWeeks:"4-6 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Savoykål är tvåårig - hon sätter frö först andra året. Huvudet måste övervintras och planteras ut igen på våren. Krävande men givande för den som vill bevara gamla sorter.",steps:["Välj det finaste, friskaste huvudet och skörda det med roten kvar","Förvara hela plantan svalt (0-5°C) över vintern - källare eller jordkällare fungerar","Plantera ut igen på våren med intakt rot och huvudstump","Huvudet spricker upp och en blomstjälk växer upp ur mitten","Gula blommor pollineras av insekter - se till att bara EN sort av Brassica oleracea blommar","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåse","Krossa skidorna försiktigt och blås bort agnarna. Förvara svalt och torrt."],isolation:"Korsar med ALLA andra Brassica oleracea (vitkål, grönkål, broccoli, blomkål, brysselkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 1 km.",storageYears:"4-5 år",tip:"Frötagning av savoykål kräver att du kan förvara en hel kålplanta över vintern. För gamla OP-sorter som Vertus 2 är det absolut värt besväret. F1-hybrider som Wirosa ger inte äkta avkomma - satsa på OP-sorter för fröbesparing!"},storage:{shelfLife:"1-4 veckor (färsk), 1-2 månader (källare), 8-12 månader (fryst)",methods:[{method:"Kylskåp",icon:"snowflake",duration:"1-3 veckor",description:"Lägg i plastpåse med några hål i grönsakslådan. Hela huvuden håller längre än delad kål. De krusiga bladen torkar ut snabbare än vitkål - håll koll.",best:!0},{method:"Sval källare",icon:"storage",duration:"1-2 månader",description:"Häng upp och ner i sval källare (0-4°C) med roten kvar. Håller inte lika länge som vitkål men kan ge dig savoykål en bit in på vintern.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Strimla eller dela i bitar, blanchera 2 minuter, kyl i isvatten och frys i portionspåsar. Perfekt för soppor, grytor och kåldolmar under vintern.",best:!1},{method:"Kåldolmar",icon:"storage",duration:"3-4 månader (frysta)",description:"Savoykålens mjuka, krusiga blad är PERFEKTA för kåldolmar. Gör en stor sats och frys in - bättre kåldolmsblad finns inte.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Strimla tunt och torka i ugn på 50°C eller i torkmaskin. Kompakt och platssnålt. Bra krydda i soppor och grytor.",best:!1}],tips:["Savoykål lagras sämre än vitkål - planera för att använda den relativt snabbt efter skörd","Låt kålen stå kvar i landet så länge som möjligt - hon tål frost bra och kylan gör henne godare","Gör kåldolmar! Savoykålens mjuka, böjliga blad är som gjorda för ändamålet - oändligt mycket bättre än vitkålsblad","Strimla och blanchera för frysning direkt efter skörd - det bevarar smak och näring bäst","Kolla lagrad kål regelbundet och ta bort blad som börjar bli sladdriga - inuti är den ofta helt fin"]},harvestCalc:{minPerSqm:2,maxPerSqm:5,unit:"kg"}};export{a as savoykal};
